"use client";

type SideTab = "analysis" | "warnings";
type DiffRow = { type: "add" | "remove" | "context"; text: string };
type AnalysisItem = { id: string; item_type: string; title?: string | null; severity?: string | null; content: string; is_selected: boolean };
type WorkflowStep = {
  id: string;
  step_key: string;
  status: string;
  version?: number;
  attempt_no?: number;
  provider_mode?: string | null;
  provider?: string | null;
  model?: string | null;
  profile_name?: string | null;
  invalidated_by_step?: string | null;
  machine_output_snapshot?: unknown;
  effective_output_snapshot?: Record<string, unknown> | null;
  attempts?: Record<string, unknown>[];
  edited_reason?: string | null;
  fallback_count?: number | null;
};

type SidebarPanelsProps = {
  sideTab: SideTab;
  analysis: { summary?: string } | null;
  analysisStore: { items: AnalysisItem[] } | null;
  issueSummary: string | null;
  visibleIssues: { id: string; issue_type: string; severity: string; source?: string | null; message: string; evidence_json?: unknown; fix_suggestion?: string | null }[];
  issues: { id: string; issue_type: string; severity: string; source?: string | null; message: string; evidence_json?: unknown; fix_suggestion?: string | null }[];
  showAllIssues: boolean;
  runtimeConnection: "idle" | "connected" | "reconnecting";
  workflow: { id: string; status: string; provider_mode?: string | null; fixture_version?: string | null; fixture_scenario?: string | null; retry_count?: number; needs_merge?: boolean; quality_degraded?: boolean; resume_checkpoint?: string | null; resume_from_step?: string | null; worker_id?: string | null; lease_expires_at?: string | null; steps: WorkflowStep[] } | null;
  runtimeSelfCheck: { backend_root: { message: string }; health: { status: string; schema_ready: boolean; provider_runtime_ready: boolean; version: string }; workflow_runtime: { workflow_runner_started: boolean; recovery_scan_completed: boolean; last_startup_stage: string; startup_error?: string | null }; knowledge: { pgvector_ready: boolean; retrieval_mode: string; retrieval_reason: string }; provider_matrix: { rule_count: number; steps: string[] }; provider_runtime: { ok: boolean; blocked_steps: string[]; providers_with_open_circuit: string[]; providers_disabled: string[] }; recommended_checks: Record<string, string[]> } | null;
  workflowRuntimeEvents: { event: string; step?: string | null; provider?: string | null; message?: string | null; created_at?: string }[];
  workflowEventCounts: Record<string, number>;
  busyKey: string;
  workflowPreview: string;
  workflowAutoApplied: boolean;
  workflowSafeToApply: boolean;
  rejectedPreview: string;
  selectedWorkflowStep: WorkflowStep | null;
  selectedWorkflowStepDiffRows: DiffRow[];
  selectedStyleHardHits: string[];
  selectedStyleSoftHits: string[];
  selectedRewriteSuggestions: string[];
  selectedNegativeMatches: Record<string, unknown>[];
  selectedGuardSafeToApply: boolean | null;
  selectedGuardNeedsRewrite: boolean | null;
  selectedGuardNeedsUserReview: boolean | null;
  activeContextSnapshot: { hard_filters?: string[]; hard_filter_result?: Record<string, unknown>; scope_resolution?: Record<string, unknown>; source_diversity_applied?: Record<string, unknown>; budget?: Record<string, unknown>; summary_reason?: string | null; deduped_sources?: string[]; clipped_sources?: string[]; candidates?: { source_type: string; source_id: string; title: string; score: number; diversity_slot?: string | null; summary_applied?: boolean }[]; summary_output?: unknown[] } | null;
  workflowViolations: { type?: string | null; severity?: string | null; rule_id?: string | null; reason?: string | null; span?: string | null; suggestion?: string | null }[];
  plannerOverrideDraft: string;
  providerSettings: { provider: "openai" | "deepseek" | "xai"; api_base: string; has_api_key: boolean; api_key_masked?: string | null; api_key?: string }[];
  providerRuntime: { providers: { provider: string; enabled: boolean; consecutive_failures: number; remaining_cooldown_seconds: number; open_until?: string | null; enabled_reason?: string | null; last_error?: string | null }[]; steps: { step: string; ready: boolean; candidate_profiles: string[]; blocking_reasons: string[] }[]; profiles: { profile_name: string; provider: string; model: string; task_type?: string | null; workflow_step?: string | null; spent_usd: number; monthly_budget_usd?: number | null; requests_per_minute?: number | null; enabled: boolean; skip_reason?: string | null }[] } | null;
  latestBackendSmoke: { report_type: "backend_full_smoke" | "frontend_live_smoke"; provider_mode?: string | null; success: boolean; failure_stage?: string | null; scenario_count: number; created_at: string; filename: string } | null;
  latestFrontendSmoke: { report_type: "backend_full_smoke" | "frontend_live_smoke"; provider_mode?: string | null; success: boolean; failure_stage?: string | null; scenario_count: number; created_at: string; filename: string } | null;
  smokeReports: { filename: string; report_type: "backend_full_smoke" | "frontend_live_smoke"; provider_mode?: string | null }[];
  selectedSmokeReportFilename: string;
  selectedSmokeReport: { report_type: "backend_full_smoke" | "frontend_live_smoke"; provider_mode?: string | null; effective_provider_mode?: string | null; success: boolean; failure_stage?: string | null; scenario_count: number; created_at: string; blocking_reasons: string[]; provider_preflight?: unknown; scenarios: { name: string; fixture_scenario?: string | null; expected_status?: string | null; actual_status?: string | null; resume_checkpoint?: string | null; event_summary?: { count?: number; counts?: Record<string, number> }; assertions: { name: string; ok: boolean; detail?: string | null }[]; step_statuses: { step_key: string; status: string; provider_mode?: string | null; provider?: string | null; model?: string | null; profile_name?: string | null }[] }[]; frontend_summary?: { url?: string | null; status_code?: number | null; created_at?: string | null; markers: Record<string, boolean> } | null } | null;
  selectedSmokeRegression: { comparable: boolean; regression_free: boolean; findings: { scope: string; key: string; message: string; baseline_value?: unknown; current_value?: unknown }[]; current_report: { filename: string; provider_mode?: string | null; success: boolean; failure_stage?: string | null }; baseline_report?: { filename: string; provider_mode?: string | null; success: boolean; created_at: string } | null } | null;
  backendSmokeReports: { filename: string }[];
  frontendSmokeReports: { filename: string }[];
  timeline: { id: string; title: string; event_time_label?: string | null }[];
  memories: { id: string; status: string; content: string }[];
  knowledgeHits: { chunk_id: string; document_title: string; source_label?: string | null; score: number; confirmed?: boolean | null; content: string }[];
  recentScenes: { scene_id: string; scene_no: number; title: string }[];
  vnExport: { markdown_script: string; image_prompts: string[] } | null;
  providerMatrix: { step: string; default_provider: string; default_model: string; timeout_ms: number; retry_count: number; fallback_targets: { provider: string; model: string }[]; fallback_to_ollama_when: string; quality_degraded_on_fallback: boolean }[];
  onSideTabChange: (value: SideTab) => void;
  onCopyGuidance: () => void;
  onToggleAnalysisItem: (itemId: string, nextSelected: boolean) => void;
  onToggleShowAllIssues: () => void;
  onRetryWorkflow: () => void;
  onCancelWorkflow: () => void;
  onSelectedWorkflowStepIdChange: (value: string) => void;
  onPlannerOverrideDraftChange: (value: string) => void;
  onOverridePlannerStep: () => void;
  onRefreshRuntime: () => void;
  onUpdateProviderField: (provider: "openai" | "deepseek" | "xai", field: "api_key" | "api_base", value: string) => void;
  onSaveProviderSettings: () => void;
  onRefreshProviderRuntime: () => void;
  onRefreshSmokeConsole: () => void;
  onSelectedSmokeReportFilenameChange: (value: string) => void;
  buttonClass: (base: string, busy?: boolean) => string;
  displaySeverityLabel: Record<string, string>;
  displayIssueLabel: Record<string, string>;
  displayIssueSource: (value?: string | null) => string;
  deriveIssueSuggestion: (issue: { id: string; issue_type: string; severity: string; source?: string | null; message: string; evidence_json?: unknown; fix_suggestion?: string | null }) => string;
  workflowStatusText: (status?: string | null) => string;
  displayStepTitle: (step: WorkflowStep) => string;
  snapshotToText: (value: unknown) => string;
  formatTime: (value?: string | null) => string;
  lineClass: (type: DiffRow["type"]) => string;
  smokeReportTypeLabel: (reportType: "backend_full_smoke" | "frontend_live_smoke", providerMode?: string | null) => string;
  smokeScenarioOutcomeLabel: (scenario: { name: string; actual_status?: string | null }) => string;
};

export function SidebarPanels(props: SidebarPanelsProps) {
  const {
    sideTab, analysis, analysisStore, issueSummary, visibleIssues, issues, showAllIssues,
    runtimeConnection, workflow, runtimeSelfCheck, workflowRuntimeEvents, workflowEventCounts,
    busyKey, workflowPreview, workflowAutoApplied, workflowSafeToApply, rejectedPreview,
    selectedWorkflowStep, selectedWorkflowStepDiffRows, selectedStyleHardHits, selectedStyleSoftHits,
    selectedRewriteSuggestions, selectedNegativeMatches, selectedGuardSafeToApply,
    selectedGuardNeedsRewrite, selectedGuardNeedsUserReview, activeContextSnapshot,
    workflowViolations, plannerOverrideDraft, providerSettings, providerRuntime,
    latestBackendSmoke, latestFrontendSmoke, smokeReports, selectedSmokeReportFilename,
    selectedSmokeReport, selectedSmokeRegression, backendSmokeReports, frontendSmokeReports,
    timeline, memories, knowledgeHits, recentScenes, vnExport, providerMatrix,
    onSideTabChange, onCopyGuidance, onToggleAnalysisItem, onToggleShowAllIssues,
    onRetryWorkflow, onCancelWorkflow, onSelectedWorkflowStepIdChange,
    onPlannerOverrideDraftChange, onOverridePlannerStep, onRefreshRuntime,
    onUpdateProviderField, onSaveProviderSettings, onRefreshProviderRuntime,
    onRefreshSmokeConsole, onSelectedSmokeReportFilenameChange, buttonClass,
    displaySeverityLabel, displayIssueLabel, displayIssueSource, deriveIssueSuggestion,
    workflowStatusText, displayStepTitle, snapshotToText, formatTime, lineClass,
    smokeReportTypeLabel, smokeScenarioOutcomeLabel,
  } = props;

  return (
    <aside className="space-y-6">
      <section className="rounded-3xl border border-white/8 bg-zinc-900/80 p-5 shadow-2xl">
        <div className="flex items-center justify-between"><h2 className="text-xl font-semibold">分析与一致性</h2><div className="flex overflow-hidden rounded-full border border-white/10"><button className={`px-4 py-2 text-sm ${sideTab === "analysis" ? "bg-zinc-100 text-black" : ""}`} onClick={() => onSideTabChange("analysis")}>分析</button><button className={`px-4 py-2 text-sm ${sideTab === "warnings" ? "bg-zinc-100 text-black" : ""}`} onClick={() => onSideTabChange("warnings")}>一致性</button></div></div>
        {sideTab === "analysis" ? <div className="mt-4 space-y-4">{analysis?.summary ? <div className="rounded-2xl bg-zinc-900/70 px-4 py-3 text-sm leading-7">{analysis.summary}</div> : null}<div className="flex items-center justify-between"><div className="text-sm font-medium">已选写作提示</div><button className="rounded-full border border-white/10 px-3 py-1.5 text-xs" onClick={onCopyGuidance}>复制已选提示</button></div><div className="space-y-2">{(analysisStore?.items ?? []).length ? analysisStore?.items.map((item) => <label key={item.id} className="flex gap-3 rounded-2xl bg-zinc-900/70 px-3 py-3 text-sm"><input type="checkbox" className="mt-1" checked={item.is_selected} onChange={(event) => onToggleAnalysisItem(item.id, event.target.checked)} /><div><div className="font-medium">{item.title || item.item_type}{item.severity ? ` · ${displaySeverityLabel[item.severity] ?? item.severity}` : ""}</div><div className="mt-1">{item.content}</div></div></label>) : <div className="rounded-2xl border border-dashed border-white/10 px-3 py-6 text-sm text-zinc-500">先跑一次分析，才能选择提示。</div>}</div></div> : <div className="mt-4 space-y-3"><div className="rounded-2xl bg-zinc-900/70 px-4 py-3 text-sm">{issueSummary || "还没有扫描结果。"}</div>{visibleIssues.length ? visibleIssues.map((issue) => <div key={issue.id} className={`rounded-2xl px-4 py-3 ${issue.severity === "high" ? "border border-rose-400/15 bg-rose-500/10 text-rose-100" : "bg-zinc-900/70"}`}><div className="flex items-start justify-between gap-4"><div><div className="text-sm font-semibold">{displayIssueLabel[issue.issue_type] ?? issue.issue_type}</div><div className="mt-1 text-xs text-zinc-500">严重度：{displaySeverityLabel[issue.severity] ?? issue.severity}</div></div><div className="rounded-full bg-zinc-950 px-3 py-1 text-xs text-zinc-500">{displayIssueSource(issue.source)}</div></div><div className="mt-3 text-sm leading-6">{issue.message}</div>{issue.evidence_json ? <pre className="mt-3 whitespace-pre-wrap rounded-xl bg-zinc-950 px-3 py-3 text-xs leading-6">{JSON.stringify(issue.evidence_json, null, 2)}</pre> : null}<div className="mt-3 text-xs text-zinc-500">建议动作：{deriveIssueSuggestion(issue)}</div></div>) : <div className="rounded-2xl border border-dashed border-white/10 px-4 py-6 text-sm text-zinc-500">还没有一致性问题。</div>}{issues.length > visibleIssues.length ? <button className="rounded-full border border-white/10 px-4 py-2 text-sm" onClick={onToggleShowAllIssues}>{showAllIssues ? "收起其余问题" : `查看更多 (${issues.length - visibleIssues.length})`}</button> : null}</div>}
      </section>

      <section className="rounded-3xl border border-white/8 bg-zinc-900/80 p-5 shadow-2xl">
        <div className="flex items-start justify-between gap-4"><div><h2 className="text-xl font-semibold">Workflow Debug</h2><p className="mt-1 text-sm text-zinc-500">Single source of truth for run state, step snapshots, resume checkpoints, and structured review signals.</p></div><div className="text-right text-xs text-zinc-500"><div>WS: {runtimeConnection === "connected" ? "connected" : runtimeConnection === "reconnecting" ? "reconnecting" : "idle"}</div><div>run: {workflowStatusText(workflow?.status)}</div><div>checkpoint: {workflow?.resume_checkpoint || "n/a"}</div></div></div>
        <div className="mt-4 grid gap-3 text-xs text-zinc-500 sm:grid-cols-2 lg:grid-cols-3"><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">resume_from_step: {workflow?.resume_from_step || "n/a"}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">needs_merge: {workflow?.needs_merge ? "true" : "false"}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">quality_degraded: {workflow?.quality_degraded ? "true" : "false"}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">provider_mode: {workflow?.provider_mode || "live"}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">fixture_version: {workflow?.fixture_version || "n/a"}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">fixture_scenario: {workflow?.fixture_scenario || "n/a"}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">worker: {workflow?.worker_id || "n/a"}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">lease_expires_at: {workflow?.lease_expires_at ? formatTime(workflow.lease_expires_at) : "n/a"}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">retry_count: {workflow?.retry_count ?? 0}</div></div>
        {workflow?.provider_mode === "smoke_fixture" ? <div className="mt-4 rounded-2xl border border-amber-400/15 bg-amber-500/10 px-4 py-4 text-sm text-amber-100">Deterministic Run: this workflow is using `smoke_fixture`, not live providers.</div> : null}
        {workflow?.provider_mode === "smoke_fixture" ? <div className="mt-4 rounded-2xl bg-zinc-900/70 px-4 py-4 text-sm text-zinc-300">Fixture Scenario: {workflow.fixture_scenario || "happy_path"}{workflow.fixture_scenario === "happy_path" ? " | smoke acceptance baseline" : " | deterministic acceptance branch"}</div> : null}
        {runtimeSelfCheck?.workflow_runtime?.startup_error ? <div className="mt-4 rounded-2xl border border-rose-400/15 bg-rose-500/10 px-4 py-4 text-sm text-rose-100">Runtime Self-Check Alert: startup issue at `{runtimeSelfCheck.workflow_runtime.last_startup_stage}`. {runtimeSelfCheck.workflow_runtime.startup_error}</div> : null}
        {workflowRuntimeEvents.length ? <div className="mt-4 space-y-3"><div className="grid gap-3 text-xs text-zinc-500 sm:grid-cols-2 lg:grid-cols-3"><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">event_count: {workflowRuntimeEvents.length}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">step_started: {workflowEventCounts.step_started ?? 0}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">step_completed: {workflowEventCounts.step_completed ?? 0}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">step_failed: {workflowEventCounts.step_failed ?? 0}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">workflow_waiting_review: {workflowEventCounts.workflow_waiting_review ?? 0}</div><div className="rounded-2xl bg-zinc-900/70 px-3 py-3">workflow_resumed: {workflowEventCounts.workflow_resumed ?? 0}</div></div><div className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs text-zinc-300"><div className="font-semibold text-zinc-100">Recent Runtime Events</div><div className="mt-2 space-y-2">{workflowRuntimeEvents.slice(-8).reverse().map((item, index) => <div key={`${item.event}-${item.created_at ?? index}`} className="rounded-xl bg-zinc-950 px-3 py-2">{item.event} | step: {item.step || "n/a"} | provider: {item.provider || "n/a"} | message: {item.message || "n/a"}</div>)}</div></div></div> : null}
        <div className="mt-4 flex flex-wrap gap-3"><button className={buttonClass("rounded-full border border-white/10 px-4 py-2 text-sm", busyKey === "retryWorkflow")} onClick={onRetryWorkflow} disabled={!workflow?.id || busyKey === "retryWorkflow"}>{busyKey === "retryWorkflow" ? "Retrying..." : "Resume / Retry"}</button><button className={buttonClass("rounded-full border border-white/10 px-4 py-2 text-sm", busyKey === "cancelWorkflow")} onClick={onCancelWorkflow} disabled={!workflow?.id || busyKey === "cancelWorkflow"}>{busyKey === "cancelWorkflow" ? "Cancelling..." : "Cancel"}</button></div>
        {workflowPreview ? <div className="mt-4 rounded-2xl bg-zinc-900/70 px-4 py-4 text-sm text-zinc-300">{workflowAutoApplied ? "Workflow output was auto-applied to the scene." : workflowSafeToApply ? "Workflow output is safe but still awaiting manual application." : "Workflow output requires review before it can be applied."}</div> : null}
        {rejectedPreview ? <pre className="mt-4 whitespace-pre-wrap rounded-2xl border border-rose-400/15 bg-rose-500/10 px-4 py-4 text-xs leading-6 text-rose-100">{rejectedPreview}</pre> : null}
        <div className="mt-4 space-y-3"><select className="w-full rounded-2xl border border-white/10 px-3 py-3 text-sm" value={selectedWorkflowStep?.id ?? ""} onChange={(event) => onSelectedWorkflowStepIdChange(event.target.value)}><option value="">Select step</option>{(workflow?.steps ?? []).map((step) => <option key={step.id} value={step.id}>{displayStepTitle(step)} - {workflowStatusText(step.status)} - v{step.version ?? 0}/a{step.attempt_no ?? 0}</option>)}</select>{(workflow?.steps ?? []).length ? <div className="grid gap-3">{(workflow?.steps ?? []).map((step) => <button key={step.id} type="button" className={`rounded-2xl border px-4 py-3 text-left text-xs ${selectedWorkflowStep?.id === step.id ? "border-zinc-100 bg-zinc-100 text-black" : "border-white/10 bg-zinc-900/70 text-zinc-300"}`} onClick={() => onSelectedWorkflowStepIdChange(step.id)}><div className="font-semibold">{displayStepTitle(step)}</div><div className="mt-1">status: {workflowStatusText(step.status)} | version: {step.version ?? 0} | attempt: {step.attempt_no ?? 0}</div><div className="mt-1">provider_mode: {step.provider_mode || workflow?.provider_mode || "live"} | provider: {step.provider || "n/a"} | model: {step.model || "n/a"}</div><div className="mt-1">profile_name: {step.profile_name || "n/a"} | fallback_count: {step.fallback_count ?? 0}</div><div className="mt-1">invalidated_by_step: {step.invalidated_by_step || "n/a"}</div></button>)}</div> : null}
          {selectedWorkflowStep ? <><div className="grid gap-4 lg:grid-cols-2"><div><div className="mb-2 text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">Machine Snapshot</div><pre className="min-h-[180px] whitespace-pre-wrap rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6">{snapshotToText(selectedWorkflowStep.machine_output_snapshot)}</pre></div><div><div className="mb-2 text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">Effective Snapshot</div><pre className="min-h-[180px] whitespace-pre-wrap rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6">{snapshotToText(selectedWorkflowStep.effective_output_snapshot)}</pre></div></div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3 text-xs text-zinc-300">provider_mode: {selectedWorkflowStep.provider_mode || workflow?.provider_mode || "live"} | provider: {selectedWorkflowStep.provider || "n/a"} | model: {selectedWorkflowStep.model || "n/a"} | profile_name: {selectedWorkflowStep.profile_name || "n/a"}</div>{selectedWorkflowStep.edited_reason ? <div className="rounded-2xl bg-zinc-900/70 px-4 py-3 text-xs text-zinc-300">edited_reason: {selectedWorkflowStep.edited_reason}</div> : null}{selectedWorkflowStepDiffRows.length ? <div className="space-y-1">{selectedWorkflowStepDiffRows.map((row, index) => <div key={`${row.type}-${index}`} className={`rounded-xl px-3 py-2 text-xs ${lineClass(row.type)}`}>{row.type === "add" ? "+ " : row.type === "remove" ? "- " : "  "}{row.text || " "}</div>)}</div> : null}{(selectedWorkflowStep.attempts ?? []).length ? <pre className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6">{JSON.stringify(selectedWorkflowStep.attempts, null, 2)}</pre> : null}{selectedWorkflowStep.step_key === "style" ? <div className="grid gap-3 lg:grid-cols-2"><div className="rounded-2xl border border-rose-400/15 bg-rose-500/10 px-4 py-3 text-xs text-rose-100"><div className="font-semibold">hard hits</div><div className="mt-2">{selectedStyleHardHits.length ? selectedStyleHardHits.join(", ") : "none"}</div></div><div className="rounded-2xl border border-amber-400/15 bg-amber-500/10 px-4 py-3 text-xs text-amber-100"><div className="font-semibold">soft hits</div><div className="mt-2">{selectedStyleSoftHits.length ? selectedStyleSoftHits.join(", ") : "none"}</div></div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3 text-xs text-zinc-300 lg:col-span-2"><div className="font-semibold text-zinc-100">rewrite_suggestions</div><div className="mt-2 space-y-1">{selectedRewriteSuggestions.length ? selectedRewriteSuggestions.map((item, index) => <div key={`${item}-${index}`}>{item}</div>) : <div>none</div>}</div></div></div> : null}{selectedNegativeMatches.length ? <div className="space-y-2">{selectedNegativeMatches.map((item, index) => <div key={`${String(item.rule_id ?? "negative")}-${index}`} className={`rounded-2xl px-4 py-3 text-xs ${item.severity === "hard" ? "border border-rose-400/15 bg-rose-500/10 text-rose-100" : "border border-amber-400/15 bg-amber-500/10 text-amber-100"}`}><div>{String(item.label ?? "negative")} | {String(item.severity ?? "unknown")} | {String(item.match_mode ?? "n/a")}</div><div className="mt-1">{String(item.reason ?? "No reason")}</div><div className="mt-1 opacity-80">match: {String(item.matched_text ?? "n/a")} | source: {String(item.source ?? "n/a")}</div></div>)}</div> : null}{selectedWorkflowStep.step_key === "guard" ? <div className="grid gap-3 text-xs text-zinc-300 sm:grid-cols-3"><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">safe_to_apply: {selectedGuardSafeToApply === null ? "n/a" : selectedGuardSafeToApply ? "true" : "false"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">needs_rewrite: {selectedGuardNeedsRewrite === null ? "n/a" : selectedGuardNeedsRewrite ? "true" : "false"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">needs_user_review: {selectedGuardNeedsUserReview === null ? "n/a" : selectedGuardNeedsUserReview ? "true" : "false"}</div></div> : null}{activeContextSnapshot ? <div className="rounded-2xl bg-zinc-900/70 px-4 py-3 text-xs text-zinc-300"><div className="font-semibold text-zinc-100">context_compile_snapshot</div><div className="mt-2">candidates: {(activeContextSnapshot.candidates ?? []).length} | summary_reason: {activeContextSnapshot.summary_reason || "n/a"} | clipped_sources: {(activeContextSnapshot.clipped_sources ?? []).length}</div></div> : null}{workflowViolations.length ? <div className="space-y-2">{workflowViolations.map((item, index) => <div key={`${item.rule_id || item.type || "violation"}-${index}`} className="rounded-2xl border border-rose-400/15 bg-rose-500/10 px-4 py-3 text-xs text-rose-100"><div>{item.type || "violation"} | {item.severity || "unknown"} | {item.rule_id || "no-rule-id"}</div><div className="mt-1">{item.reason || "No reason provided"}</div><div className="mt-1 text-rose-200/80">span: {item.span || "n/a"} | suggestion: {item.suggestion || "n/a"}</div></div>)}</div> : null}{selectedWorkflowStep.step_key === "plan" ? <div className="rounded-2xl bg-zinc-900/70 px-4 py-4"><div className="flex items-center justify-between gap-3"><div><div className="text-sm font-semibold text-zinc-100">Planner Override</div><div className="mt-1 text-xs text-zinc-500">Submitting this will call `/resume` automatically and continue from `write`.</div></div><button className={buttonClass("rounded-full bg-zinc-100 px-4 py-2 text-xs text-black", busyKey === "retryWorkflow")} onClick={onOverridePlannerStep} disabled={busyKey === "retryWorkflow"}>{busyKey === "retryWorkflow" ? "Submitting..." : "Submit Override"}</button></div><textarea className="mt-3 min-h-[180px] w-full rounded-2xl border border-white/10 bg-zinc-950 px-4 py-3 font-mono text-xs leading-6 text-zinc-200" value={plannerOverrideDraft} onChange={(event) => onPlannerOverrideDraftChange(event.target.value)} /></div> : null}</> : <div className="rounded-2xl border border-dashed border-white/10 px-4 py-6 text-sm text-zinc-500">Run a workflow and then pick a step to inspect the structured debug view.</div>}
        </div>
      </section>

      <section className="rounded-3xl border border-white/8 bg-zinc-900/80 p-5 shadow-2xl">
        <div className="flex items-center justify-between gap-4"><div><h2 className="text-xl font-semibold">Runtime Readiness</h2><p className="mt-1 text-sm text-zinc-500">Health and self-check results for startup, recovery, pgvector readiness, and provider matrix availability.</p></div><button className="rounded-full border border-white/10 px-4 py-2 text-sm" onClick={onRefreshRuntime}>Refresh</button></div>
        {runtimeSelfCheck ? <div className="mt-4 space-y-3 text-sm text-zinc-300"><div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3"><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">health: {runtimeSelfCheck.health.status}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">schema_ready: {runtimeSelfCheck.health.schema_ready ? "true" : "false"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">runner_started: {runtimeSelfCheck.workflow_runtime.workflow_runner_started ? "true" : "false"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">recovery_scan_completed: {runtimeSelfCheck.workflow_runtime.recovery_scan_completed ? "true" : "false"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">pgvector_ready: {runtimeSelfCheck.knowledge.pgvector_ready ? "true" : "false"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">provider_rules: {runtimeSelfCheck.provider_matrix.rule_count}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">provider_runtime_ready: {runtimeSelfCheck.health.provider_runtime_ready ? "true" : "false"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">provider_runtime.ok: {runtimeSelfCheck.provider_runtime.ok ? "true" : "false"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">blocked_steps: {runtimeSelfCheck.provider_runtime.blocked_steps.join(", ") || "none"}</div></div><div className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6"><div>backend_root: {runtimeSelfCheck.backend_root.message}</div><div>startup_stage: {runtimeSelfCheck.workflow_runtime.last_startup_stage}</div><div>retrieval_mode: {runtimeSelfCheck.knowledge.retrieval_mode}</div><div>retrieval_reason: {runtimeSelfCheck.knowledge.retrieval_reason}</div><div>provider_steps: {runtimeSelfCheck.provider_matrix.steps.join(", ") || "none"}</div><div>version: {runtimeSelfCheck.health.version}</div><div>open_circuit: {runtimeSelfCheck.provider_runtime.providers_with_open_circuit.join(", ") || "none"}</div><div>disabled: {runtimeSelfCheck.provider_runtime.providers_disabled.join(", ") || "none"}</div></div><div className={`rounded-2xl border px-4 py-4 text-sm ${runtimeSelfCheck.workflow_runtime.startup_error ? "border-rose-400/15 bg-rose-500/10 text-rose-100" : "border-emerald-400/15 bg-emerald-500/10 text-emerald-100"}`}>Runtime Self-Check Alert: {runtimeSelfCheck.workflow_runtime.startup_error ? runtimeSelfCheck.workflow_runtime.startup_error : "none"}</div><div className={`rounded-2xl border px-4 py-4 text-sm ${runtimeSelfCheck.provider_runtime.ok ? "border-emerald-400/15 bg-emerald-500/10 text-emerald-100" : "border-rose-400/15 bg-rose-500/10 text-rose-100"}`}>Provider Runtime Alert: {runtimeSelfCheck.provider_runtime.ok ? "none" : runtimeSelfCheck.provider_runtime.blocked_steps.join(", ") || "provider runtime blocked"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6">{Object.entries(runtimeSelfCheck.recommended_checks).map(([group, commands]) => <div key={group} className="mb-2 last:mb-0"><div className="font-semibold text-zinc-100">{group}</div><div className="mt-1 space-y-1">{commands.map((command) => <div key={command}>{command}</div>)}</div></div>)}</div></div> : <div className="mt-4 rounded-2xl border border-dashed border-white/10 px-4 py-6 text-sm text-zinc-500">Runtime Self-Check Alert: waiting for load.</div>}
      </section>

      <section className="rounded-3xl border border-white/8 bg-zinc-900/80 p-5 shadow-2xl">
        <div className="flex items-center justify-between gap-4"><div><h2 className="text-xl font-semibold">Cloud API Config</h2><p className="mt-1 text-sm text-zinc-500">Save your OpenAI, DeepSeek, and xAI API keys here. After saving, workflow calls will prefer these cloud settings.</p></div><button className={buttonClass("rounded-full bg-zinc-100 px-4 py-2 text-sm text-black", busyKey === "saveProviderSettings")} onClick={onSaveProviderSettings} disabled={busyKey === "saveProviderSettings"}>{busyKey === "saveProviderSettings" ? "Saving..." : "Save API Config"}</button></div>
        <div className="mt-4 space-y-4">{providerSettings.map((item) => <div key={item.provider} className="rounded-2xl bg-zinc-900/70 px-4 py-4"><div className="flex items-center justify-between gap-4"><div className="text-sm font-semibold text-zinc-100">{item.provider === "openai" ? "OpenAI" : item.provider === "deepseek" ? "DeepSeek" : "xAI / Grok"}</div><div className="text-xs text-zinc-500">{item.has_api_key ? `Saved: ${item.api_key_masked ?? "configured"}` : "No API key saved yet"}</div></div><div className="mt-3 grid gap-3"><input className="w-full rounded-2xl border border-white/10 bg-zinc-950 px-3 py-3 text-sm" value={item.api_base} onChange={(event) => onUpdateProviderField(item.provider, "api_base", event.target.value)} placeholder="API Base URL" /><input className="w-full rounded-2xl border border-white/10 bg-zinc-950 px-3 py-3 text-sm" type="password" value={item.api_key ?? ""} onChange={(event) => onUpdateProviderField(item.provider, "api_key", event.target.value)} placeholder={item.has_api_key ? "Leave blank to keep the saved key; enter a new value to replace it" : "Paste API key here"} /></div></div>)}</div>
      </section>

      <section className="rounded-3xl border border-white/8 bg-zinc-900/80 p-5 shadow-2xl">
        <div className="flex items-center justify-between gap-4"><div><h2 className="text-xl font-semibold">Provider Runtime</h2><p className="mt-1 text-sm text-zinc-500">Read-only provider runtime state, profile skip reasons, and smoke-step readiness.</p></div><button className="rounded-full border border-white/10 px-4 py-2 text-sm" onClick={onRefreshProviderRuntime}>Refresh</button></div>
        {providerRuntime ? <div className="mt-4 space-y-4 text-sm text-zinc-300"><div className={`rounded-2xl border px-4 py-4 text-sm ${runtimeSelfCheck?.provider_runtime.ok === false ? "border-rose-400/15 bg-rose-500/10 text-rose-100" : "border-emerald-400/15 bg-emerald-500/10 text-emerald-100"}`}>Provider Runtime Alert: {runtimeSelfCheck?.provider_runtime.ok === false ? runtimeSelfCheck.provider_runtime.blocked_steps.join(", ") || "blocked" : "none"}</div><div className="grid gap-3 lg:grid-cols-2">{providerRuntime.providers.map((item) => <div key={item.provider} className={`rounded-2xl px-4 py-4 text-xs ${item.enabled && item.remaining_cooldown_seconds === 0 ? "bg-zinc-900/70 text-zinc-300" : "border border-rose-400/15 bg-rose-500/10 text-rose-100"}`}><div className="font-semibold text-sm text-zinc-100">{item.provider}</div><div className="mt-2">enabled: {item.enabled ? "true" : "false"}</div><div>consecutive_failures: {item.consecutive_failures}</div><div>remaining_cooldown_seconds: {item.remaining_cooldown_seconds}</div><div>open_until: {item.open_until || "n/a"}</div><div>enabled_reason: {item.enabled_reason || "none"}</div><div>last_error: {item.last_error || "none"}</div></div>)}</div><div className="grid gap-3 lg:grid-cols-2">{providerRuntime.steps.map((item) => <div key={item.step} className={`rounded-2xl border px-4 py-4 text-xs ${item.ready ? "border-emerald-400/15 bg-emerald-500/10 text-emerald-100" : "border-rose-400/15 bg-rose-500/10 text-rose-100"}`}><div className="font-semibold text-sm text-zinc-100">{item.step}</div><div className="mt-2">ready: {item.ready ? "true" : "false"}</div><div>candidate_profiles: {item.candidate_profiles.join(", ") || "none"}</div><div>blocking_reasons: {item.blocking_reasons.join(" | ") || "none"}</div></div>)}</div><div className="space-y-3">{providerRuntime.profiles.map((item) => <div key={`${item.profile_name}-${item.provider}-${item.model}`} className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs text-zinc-300"><div className="font-semibold text-zinc-100">{item.profile_name}</div><div className="mt-1">provider/model: {item.provider} / {item.model}</div><div>task_type/workflow_step: {item.task_type || "n/a"} / {item.workflow_step || "n/a"}</div><div>spent/budget: {item.spent_usd} / {item.monthly_budget_usd ?? "n/a"}</div><div>requests_per_minute: {item.requests_per_minute ?? "n/a"}</div><div>enabled: {item.enabled ? "true" : "false"}</div><div>skip_reason: {item.skip_reason || "none"}</div></div>)}</div></div> : <div className="mt-4 rounded-2xl border border-dashed border-white/10 px-4 py-6 text-sm text-zinc-500">Provider Runtime Alert: waiting for load.</div>}
      </section>

      <section className="rounded-3xl border border-white/8 bg-zinc-900/80 p-5 shadow-2xl">
        <div className="flex items-center justify-between gap-4"><div><h2 className="text-xl font-semibold">Smoke Console</h2><p className="mt-1 text-sm text-zinc-500">Read-only acceptance report browser for fixture smoke, live provider smoke, and frontend live UI smoke.</p></div><button className="rounded-full border border-white/10 px-4 py-2 text-sm" onClick={onRefreshSmokeConsole}>Refresh</button></div>
        <div className="mt-4 grid gap-3 lg:grid-cols-2"><div className={`rounded-2xl px-4 py-4 text-sm ${latestBackendSmoke?.success ? "border border-emerald-400/15 bg-emerald-500/10 text-emerald-100" : "bg-zinc-900/70 text-zinc-300"}`}><div className="font-semibold text-zinc-100">Latest Backend Smoke</div>{latestBackendSmoke ? <div className="mt-2 space-y-1 text-xs leading-6"><div>type: {smokeReportTypeLabel(latestBackendSmoke.report_type, latestBackendSmoke.provider_mode)}</div><div>provider_mode: {latestBackendSmoke.provider_mode || "n/a"}</div><div>success: {latestBackendSmoke.success ? "true" : "false"}</div><div>failure_stage: {latestBackendSmoke.failure_stage || "none"}</div><div>scenario_count: {latestBackendSmoke.scenario_count}</div><div>created_at: {formatTime(latestBackendSmoke.created_at)}</div></div> : <div className="mt-2 text-xs text-zinc-500">No backend smoke report found.</div>}</div><div className={`rounded-2xl px-4 py-4 text-sm ${latestFrontendSmoke?.success ? "border border-emerald-400/15 bg-emerald-500/10 text-emerald-100" : "bg-zinc-900/70 text-zinc-300"}`}><div className="font-semibold text-zinc-100">Latest Frontend Smoke</div>{latestFrontendSmoke ? <div className="mt-2 space-y-1 text-xs leading-6"><div>type: {smokeReportTypeLabel(latestFrontendSmoke.report_type, latestFrontendSmoke.provider_mode)}</div><div>success: {latestFrontendSmoke.success ? "true" : "false"}</div><div>created_at: {formatTime(latestFrontendSmoke.created_at)}</div><div>filename: {latestFrontendSmoke.filename}</div></div> : <div className="mt-2 text-xs text-zinc-500">No frontend smoke report found.</div>}</div></div>
        {smokeReports.length ? <><div className="mt-4 grid gap-3 lg:grid-cols-2"><select className="rounded-2xl border border-white/10 bg-zinc-950 px-4 py-3 text-sm text-zinc-200" value={selectedSmokeReportFilename} onChange={(event) => onSelectedSmokeReportFilenameChange(event.target.value)}>{smokeReports.map((item) => <option key={item.filename} value={item.filename}>{smokeReportTypeLabel(item.report_type, item.provider_mode)} · {item.filename}</option>)}</select><div className="rounded-2xl bg-zinc-900/70 px-4 py-3 text-xs text-zinc-500">reports: {smokeReports.length} | backend: {backendSmokeReports.length} | frontend: {frontendSmokeReports.length}</div></div>{selectedSmokeReport ? <div className="mt-4 space-y-4 text-sm text-zinc-300"><div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3"><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">type: {smokeReportTypeLabel(selectedSmokeReport.report_type, selectedSmokeReport.provider_mode)}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">success: {selectedSmokeReport.success ? "true" : "false"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">failure_stage: {selectedSmokeReport.failure_stage || "none"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">provider_mode: {selectedSmokeReport.provider_mode || selectedSmokeReport.effective_provider_mode || "n/a"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">scenario_count: {selectedSmokeReport.scenario_count}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">created_at: {formatTime(selectedSmokeReport.created_at)}</div></div>{selectedSmokeRegression ? <div className="rounded-2xl bg-zinc-900/70 px-4 py-4"><div className="flex items-start justify-between gap-4"><div><div className="font-semibold text-zinc-100">Regression Compare</div><div className="mt-1 text-xs text-zinc-500">Automatically compared against the latest successful earlier report with the same report type and provider mode.</div></div><div className="text-right text-xs text-zinc-500"><div>comparable: {selectedSmokeRegression.comparable ? "true" : "false"}</div><div>regression_free: {selectedSmokeRegression.regression_free ? "true" : "false"}</div><div>finding_count: {selectedSmokeRegression.findings.length}</div></div></div><div className="mt-3 grid gap-3 lg:grid-cols-2"><div className="rounded-2xl bg-zinc-950 px-4 py-4 text-xs leading-6"><div className="font-semibold text-zinc-100">Current Report</div><div className="mt-2">filename: {selectedSmokeRegression.current_report.filename}</div><div>provider_mode: {selectedSmokeRegression.current_report.provider_mode || "n/a"}</div><div>success: {selectedSmokeRegression.current_report.success ? "true" : "false"}</div><div>failure_stage: {selectedSmokeRegression.current_report.failure_stage || "none"}</div></div><div className="rounded-2xl bg-zinc-950 px-4 py-4 text-xs leading-6"><div className="font-semibold text-zinc-100">Baseline Report</div>{selectedSmokeRegression.baseline_report ? <><div className="mt-2">filename: {selectedSmokeRegression.baseline_report.filename}</div><div>provider_mode: {selectedSmokeRegression.baseline_report.provider_mode || "n/a"}</div><div>success: {selectedSmokeRegression.baseline_report.success ? "true" : "false"}</div><div>created_at: {formatTime(selectedSmokeRegression.baseline_report.created_at)}</div></> : <div className="mt-2 text-zinc-500">No comparable successful baseline found yet.</div>}</div></div><div className={`mt-3 rounded-2xl border px-4 py-4 text-sm leading-6 ${selectedSmokeRegression.regression_free ? "border-emerald-400/15 bg-emerald-500/10 text-emerald-100" : "border-rose-400/15 bg-rose-500/10 text-rose-100"}`}>{selectedSmokeRegression.regression_free ? (selectedSmokeRegression.comparable ? "No regressions detected against the latest successful baseline." : "No baseline available yet, so regression compare is currently informational only.") : "Regression findings detected against the latest successful baseline."}</div>{selectedSmokeRegression.findings.length ? <div className="mt-3 space-y-2">{selectedSmokeRegression.findings.map((finding) => <div key={`${finding.scope}-${finding.key}`} className="rounded-2xl border border-rose-400/15 bg-rose-500/10 px-4 py-4 text-xs leading-6 text-rose-100"><div className="font-semibold">{finding.scope} | {finding.key}</div><div className="mt-1">{finding.message}</div><div className="mt-1 text-rose-200/80">baseline: {String(finding.baseline_value ?? "n/a")} | current: {String(finding.current_value ?? "n/a")}</div></div>)}</div> : null}</div> : null}{selectedSmokeReport.blocking_reasons.length ? <div className="rounded-2xl border border-rose-400/15 bg-rose-500/10 px-4 py-4 text-sm text-rose-100">blocking_reasons: {selectedSmokeReport.blocking_reasons.join(" | ")}</div> : null}{selectedSmokeReport.report_type === "backend_full_smoke" ? <>{selectedSmokeReport.provider_preflight ? <pre className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6">{JSON.stringify(selectedSmokeReport.provider_preflight, null, 2)}</pre> : null}<div className="space-y-3">{selectedSmokeReport.scenarios.map((scenario) => <div key={`${scenario.name}-${scenario.fixture_scenario || "default"}`} className={`rounded-2xl px-4 py-4 ${scenario.expected_status === scenario.actual_status ? "bg-zinc-900/70" : "border border-amber-400/15 bg-amber-500/10 text-amber-100"}`}><div className="flex items-start justify-between gap-4"><div><div className="font-semibold text-zinc-100">{scenario.name}</div><div className="mt-1 text-xs text-zinc-500">{smokeScenarioOutcomeLabel(scenario)}</div></div><div className="text-right text-xs text-zinc-500"><div>expected: {scenario.expected_status || "n/a"}</div><div>actual: {scenario.actual_status || "n/a"}</div><div>resume_checkpoint: {scenario.resume_checkpoint || "n/a"}</div></div></div><div className="mt-3 grid gap-3 text-xs text-zinc-300 sm:grid-cols-2 lg:grid-cols-3"><div className="rounded-2xl bg-zinc-950 px-3 py-3">step_started: {scenario.event_summary?.counts?.step_started ?? 0}</div><div className="rounded-2xl bg-zinc-950 px-3 py-3">step_completed: {scenario.event_summary?.counts?.step_completed ?? 0}</div><div className="rounded-2xl bg-zinc-950 px-3 py-3">step_failed: {scenario.event_summary?.counts?.step_failed ?? 0}</div><div className="rounded-2xl bg-zinc-950 px-3 py-3">workflow_waiting_review: {scenario.event_summary?.counts?.workflow_waiting_review ?? 0}</div><div className="rounded-2xl bg-zinc-950 px-3 py-3">workflow_resumed: {scenario.event_summary?.counts?.workflow_resumed ?? 0}</div><div className="rounded-2xl bg-zinc-950 px-3 py-3">event_count: {scenario.event_summary?.count ?? 0}</div></div><div className="mt-3 grid gap-3 lg:grid-cols-2"><div className="rounded-2xl bg-zinc-950 px-4 py-4 text-xs leading-6 text-zinc-300"><div className="font-semibold text-zinc-100">Assertions</div><div className="mt-2 space-y-2">{scenario.assertions.length ? scenario.assertions.map((assertion) => <div key={`${scenario.name}-${assertion.name}`} className={assertion.ok ? "text-emerald-200" : "text-rose-200"}>{assertion.ok ? "PASS" : "FAIL"} | {assertion.name} | {assertion.detail || "n/a"}</div>) : <div className="text-zinc-500">No assertions recorded.</div>}</div></div><div className="rounded-2xl bg-zinc-950 px-4 py-4 text-xs leading-6 text-zinc-300"><div className="font-semibold text-zinc-100">Step Statuses</div><div className="mt-2 space-y-2">{scenario.step_statuses.length ? scenario.step_statuses.map((step) => <div key={`${scenario.name}-${step.step_key}-${step.profile_name || "none"}`}>{step.step_key}: {step.status} | {step.provider_mode || "n/a"} | {step.provider || "n/a"} / {step.model || "n/a"} | {step.profile_name || "n/a"}</div>) : <div className="text-zinc-500">No step status snapshot.</div>}</div></div></div></div>)}</div></> : selectedSmokeReport.frontend_summary ? <div className="grid gap-3 lg:grid-cols-2"><div className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6"><div>url: {selectedSmokeReport.frontend_summary.url || "n/a"}</div><div>status_code: {selectedSmokeReport.frontend_summary.status_code ?? "n/a"}</div><div>created_at: {formatTime(selectedSmokeReport.frontend_summary.created_at)}</div></div><div className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6"><div className="font-semibold text-zinc-100">Stable Markers</div><div className="mt-2 space-y-1">{Object.entries(selectedSmokeReport.frontend_summary.markers).map(([key, value]) => <div key={key}>{key}: {value ? "true" : "false"}</div>)}</div></div></div> : null}</div> : <div className="mt-4 rounded-2xl border border-dashed border-white/10 px-4 py-6 text-sm text-zinc-500">Select a smoke report to inspect its structured detail.</div>}</> : <div className="mt-4 rounded-2xl border border-dashed border-white/10 px-4 py-6 text-sm text-zinc-500">No smoke reports found in `scripts/logs` yet.</div>}
      </section>

      <section className="rounded-3xl border border-white/8 bg-zinc-900/80 p-5 shadow-2xl">
        <h2 className="text-xl font-semibold">记忆上下文与 VN 导出</h2>
        <div className="mt-4 space-y-4 text-sm text-zinc-300"><div className="rounded-2xl bg-zinc-900/70 px-4 py-3"><div className="font-medium text-zinc-100">时间线</div><div className="mt-2 space-y-2">{timeline.length ? timeline.map((item) => <div key={item.id}>• {item.title} {item.event_time_label ? `· ${item.event_time_label}` : ""}</div>) : <div>暂无。</div>}</div></div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3"><div className="font-medium text-zinc-100">风格记忆</div><div className="mt-2 space-y-2">{memories.length ? memories.map((item) => <div key={item.id}>• [{item.status}] {item.content}</div>) : <div>暂无。</div>}</div></div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3"><div className="font-medium text-zinc-100">设定命中</div><div className="mt-2 space-y-3">{knowledgeHits.length ? knowledgeHits.map((item) => <div key={item.chunk_id}><div className="font-medium text-zinc-100">{item.document_title} · {item.source_label || "记忆片段"}</div><div className="mt-1 text-xs text-zinc-500">分数 {item.score.toFixed(3)} · {item.confirmed ? "已确认" : "未确认/通用"}</div><div className="mt-1">{item.content}</div></div>) : <div>暂无。</div>}</div></div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3"><div className="font-medium text-zinc-100">近期场景</div><div className="mt-2 space-y-2">{recentScenes.length ? recentScenes.map((item) => <div key={item.scene_id}>• 第 {item.scene_no} 场 {item.title}</div>) : <div>暂无。</div>}</div></div>{vnExport ? <div className="rounded-2xl border border-emerald-400/15 bg-emerald-500/10 px-4 py-3 text-emerald-100"><div className="font-medium text-emerald-100">VN 导出预览</div><pre className="mt-3 max-h-[220px] overflow-auto whitespace-pre-wrap rounded-xl bg-zinc-950 px-3 py-3 text-sm leading-6 text-zinc-200">{vnExport.markdown_script}</pre>{vnExport.image_prompts.length ? <div className="mt-3 space-y-2">{vnExport.image_prompts.map((item, index) => <div key={`${item}-${index}`}>• {item}</div>)}</div> : null}</div> : null}</div>
      </section>

      <section className="rounded-3xl border border-white/8 bg-zinc-900/80 p-5 shadow-2xl">
        <h2 className="text-xl font-semibold">Provider Matrix</h2>
        <div className="mt-4 space-y-3">{providerMatrix.length ? providerMatrix.map((rule) => <div key={rule.step} className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-sm text-zinc-300"><div className="flex items-start justify-between gap-4"><div><div className="font-semibold text-zinc-100">{rule.step}</div><div className="mt-1 text-xs text-zinc-500">{rule.default_provider} / {rule.default_model}</div></div><div className="text-right text-xs text-zinc-500"><div>timeout {rule.timeout_ms} ms</div><div>retry {rule.retry_count}</div></div></div><div className="mt-2 text-xs text-zinc-500">fallback: {rule.fallback_targets.map((item) => `${item.provider}/${item.model}`).join(" -> ") || "none"}</div><div className="mt-1 text-xs text-zinc-500">quality degraded: {rule.quality_degraded_on_fallback ? "true" : "false"}</div><div className="mt-1 text-xs text-zinc-500">{rule.fallback_to_ollama_when}</div></div>) : <div className="rounded-2xl border border-dashed border-white/10 px-4 py-6 text-sm text-zinc-500">暂未读取到 provider matrix。</div>}</div>
      </section>

      <section className="rounded-3xl border border-white/8 bg-zinc-900/80 p-5 shadow-2xl">
        <h2 className="text-xl font-semibold">Context Compiler</h2>
        {activeContextSnapshot ? <div className="mt-4 space-y-3 text-sm text-zinc-300"><div className="rounded-2xl bg-zinc-900/70 px-4 py-3 text-xs text-zinc-500">hard filters: {(activeContextSnapshot.hard_filters ?? []).join(" | ") || "none"}</div><div className="grid gap-3 sm:grid-cols-2"><pre className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6">{JSON.stringify(activeContextSnapshot.hard_filter_result ?? {}, null, 2)}</pre><pre className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6">{JSON.stringify(activeContextSnapshot.scope_resolution ?? {}, null, 2)}</pre><pre className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6">{JSON.stringify(activeContextSnapshot.source_diversity_applied ?? {}, null, 2)}</pre><pre className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6">{JSON.stringify(activeContextSnapshot.budget ?? {}, null, 2)}</pre></div><div className="grid gap-3 text-xs text-zinc-300 sm:grid-cols-3"><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">summary_reason: {activeContextSnapshot.summary_reason || "n/a"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">deduped_sources: {(activeContextSnapshot.deduped_sources ?? []).join(", ") || "none"}</div><div className="rounded-2xl bg-zinc-900/70 px-4 py-3">clipped_sources: {(activeContextSnapshot.clipped_sources ?? []).join(", ") || "none"}</div></div>{(activeContextSnapshot.candidates ?? []).slice(0, 8).map((item) => <div key={`${item.source_type}-${item.source_id}`} className="rounded-2xl bg-zinc-900/70 px-4 py-3 text-xs text-zinc-300"><div className="font-semibold text-zinc-100">{item.title}</div><div className="mt-1">type: {item.source_type} | score: {item.score.toFixed(4)} | slot: {item.diversity_slot || "n/a"}</div><div className="mt-1 text-zinc-500">{item.summary_applied ? "summary applied" : "full item"}</div></div>)}{activeContextSnapshot.summary_output?.length ? <pre className="rounded-2xl bg-zinc-900/70 px-4 py-4 text-xs leading-6">{JSON.stringify(activeContextSnapshot.summary_output, null, 2)}</pre> : null}</div> : <div className="mt-4 rounded-2xl border border-dashed border-white/10 px-4 py-6 text-sm text-zinc-500">Reload the scene to inspect the latest compile snapshot.</div>}
      </section>
    </aside>
  );
}
